@@ -585,9 +585,9 @@
  		unp_drop(ref, ECONNRESET);
  		UNP_PCB_UNLOCK(ref);
  	}
+	local_unp_rights = unp_rights;
  	UNP_GLOBAL_WUNLOCK();
  	unp->unp_socket->so_pcb = NULL;
-	local_unp_rights = unp_rights;
  	saved_unp_addr = unp->unp_addr;
  	unp->unp_addr = NULL;
  	unp->unp_refcount--;
@@ -1602,7 +1602,9 @@
  				FILE_LOCK(fp);
  				fp->f_msgcount--;
  				FILE_UNLOCK(fp);
+				UNP_GLOBAL_WLOCK();
  				unp_rights--;
+				UNP_GLOBAL_WUNLOCK();
  				*fdp++ = f;
  			}
  			FILEDESC_XUNLOCK(td->td_proc->p_fd);
@@ -1768,7 +1770,9 @@
  				fp->f_count++;
  				fp->f_msgcount++;
  				FILE_UNLOCK(fp);
+				UNP_GLOBAL_WLOCK();
  				unp_rights++;
+				UNP_GLOBAL_WUNLOCK();
  			}
  			FILEDESC_SUNLOCK(fdescp);
  			break;
